import React, { useEffect, useRef, useState } from 'react';

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [selectedPeriod, setSelectedPeriod] = useState(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const prevPeriodRef = useRef(-1); // Store last known period

  // Fetch stats from API
  const fetchStats = async (period = null) => {
    const url = period !== null
      ? `/api/dashboard-stats?period=${period}`
      : `/api/dashboard-stats`;

    const res = await fetch(url);
    const data = await res.json();
    setStats(data);

    // Update prevPeriodRef only during auto mode and valid periods
    if (period === null && data.currentPeriod !== -1) {
      prevPeriodRef.current = data.currentPeriod;
    }
  };

  // Get current period based on current time
  const getCurrentPeriod = (now) => {
    const hour = now.getHours();
    const minutes = now.getMinutes();
    const timeInMins = hour * 60 + minutes;

    const periods = [
      { start: 480, end: 530 },   // 8:00 - 8:50 (Period 1)
      { start: 530, end: 580 },   // 8:50 - 9:40 (Period 2)
      { start: 580, end: 645 },   // 9:40 - 10:45 (Break)
      { start: 645, end: 695 },   // 10:45 - 11:35 (Period 3)
      { start: 695, end: 745 },   // 11:35 - 12:25 (Period 4)
      { start: 745, end: 810 },   // 12:25 - 1:30 (Lunch)
      { start: 810, end: 860 },   // 1:30 - 2:20 (Period 5)
      { start: 860, end: 910 },   // 2:20 - 3:10 (Period 6)
      { start: 910, end: 960 },   // 3:10 - 4:00 (Period 7)
    ];

    for (let i = 0; i < periods.length; i++) {
      if (timeInMins >= periods[i].start && timeInMins < periods[i].end) {
        if (i === 2 || i === 5) return -1; // Break or lunch
        return i < 2 ? i + 1 : i - 1;      // Map to period 1–7
      }
    }

    return -1; // Outside class hours
  };

  // Update time every second
  useEffect(() => {
    const interval = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(interval);
  }, []);

  // Auto-fetch every 1 minute ONLY if period changes
  useEffect(() => {
    let autoInterval = null;

    if (selectedPeriod === null) {
      autoInterval = setInterval(() => {
        const now = new Date();
        const currentPeriod = getCurrentPeriod(now);

        if (currentPeriod !== -1 && currentPeriod !== prevPeriodRef.current) {
          fetchStats(); // Auto-fetch only when period changes
        }

        // Optional debug log
        // console.log("Now:", now.toLocaleTimeString(), "| Period:", currentPeriod, "| Prev:", prevPeriodRef.current);
      }, 60000); // Every 1 minute
    }

    return () => {
      if (autoInterval) clearInterval(autoInterval);
    };
  }, [selectedPeriod]);

  // Initial fetch on load
  useEffect(() => {
    if (selectedPeriod !== null) {
      fetchStats(selectedPeriod);
    } else {
      fetchStats();
    }
  }, [selectedPeriod]);

  const handlePeriodChange = (e) => {
    const value = e.target.value;
    if (value === 'auto') {
      setSelectedPeriod(null);
      fetchStats(); // Refetch on returning to auto
    } else {
      setSelectedPeriod(parseInt(value));
    }
  };

  const currentPeriod = selectedPeriod !== null
    ? selectedPeriod
    : getCurrentPeriod(currentTime);

  return (
    <div className="dashboard">
      <div className="status-row" style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
        <div>
          <strong>Current Time:</strong> {currentTime.toLocaleTimeString()}
        </div>
        <div>
          <strong>Current Period:</strong>{' '}
          {currentPeriod === -1 ? 'Break/Lunch' : `Period ${currentPeriod}`}
        </div>
        <div>
          <label><strong>Select Period: </strong></label>
          <select onChange={handlePeriodChange} value={selectedPeriod !== null ? selectedPeriod : 'auto'}>
            <option value="auto">Auto (Current Time)</option>
            {[1, 2, 3, 4, 5, 6, 7].map(p => (
              <option key={p} value={p}>Period {p}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Render your charts and stats below */}
      <div className="stats-section">
        {/* Replace below with your actual chart components */}
        {stats ? (
          <pre>{JSON.stringify(stats, null, 2)}</pre>
        ) : (
          <p>Loading stats...</p>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
